"use client";

import * as React from "react";
import { cn } from "../lib/cn";

export type MobileDockItem = {
  ariaLabel?: string;
  disabled?: boolean;
  href?: string;
  icon: React.ReactNode;
  label: string;
  value: string;
};

export type MobileDockAction = {
  ariaLabel?: string;
  disabled?: boolean;
  href?: string;
  icon: React.ReactNode;
  label: string;
  onClick?: (event: React.MouseEvent<HTMLElement>) => void;
};

export type MobileDockProps = Omit<React.HTMLAttributes<HTMLElement>, "onChange"> & {
  action?: MobileDockAction;
  ariaLabel?: string;
  defaultValue?: string;
  items: readonly MobileDockItem[];
  onValueChange?: (value: string, item: MobileDockItem) => void;
  position?: "fixed" | "static";
  value?: string;
};

type DockIndicator = {
  height: number;
  width: number;
  x: number;
  y: number;
};

export function MobileDock({
  action,
  ariaLabel = "Primary navigation",
  className,
  defaultValue,
  items,
  onValueChange,
  position = "fixed",
  value,
  ...props
}: MobileDockProps) {
  const firstEnabledItem = items.find((item) => !item.disabled);
  const [internalValue, setInternalValue] = React.useState(
    defaultValue ?? firstEnabledItem?.value ?? ""
  );
  const navRef = React.useRef<HTMLDivElement | null>(null);
  const itemRefs = React.useRef(new Map<string, HTMLElement>());
  const [indicator, setIndicator] = React.useState<DockIndicator | null>(null);
  const selectedValue = value ?? internalValue;
  const splitIndex = action ? Math.ceil(items.length / 2) : items.length;

  React.useLayoutEffect(() => {
    function measure() {
      const nav = navRef.current;
      const selectedItem = itemRefs.current.get(selectedValue);
      if (!nav || !selectedItem) {
        setIndicator(null);
        return;
      }
      const navBox = nav.getBoundingClientRect();
      const itemBox = selectedItem.getBoundingClientRect();
      setIndicator({
        height: itemBox.height,
        width: itemBox.width,
        x: itemBox.left - navBox.left,
        y: itemBox.top - navBox.top
      });
    }

    measure();
    window.addEventListener("resize", measure);
    return () => window.removeEventListener("resize", measure);
  }, [items, selectedValue]);

  const indicatorStyle = indicator
    ? ({
        height: `${indicator.height}px`,
        opacity: 1,
        transform: `translate3d(${indicator.x}px, ${indicator.y}px, 0)`,
        width: `${indicator.width}px`
      } satisfies React.CSSProperties)
    : ({ opacity: 0 } satisfies React.CSSProperties);

  function selectItem(item: MobileDockItem) {
    if (item.disabled) return;
    if (value === undefined) setInternalValue(item.value);
    onValueChange?.(item.value, item);
  }

  return (
    <nav
      aria-label={ariaLabel}
      className={cn(
        position === "fixed"
          ? "pointer-events-none fixed inset-x-0 bottom-[calc(18px+env(safe-area-inset-bottom))] z-30 flex justify-center px-axie-page"
          : "pointer-events-none relative flex justify-center px-axie-page py-4",
        className
      )}
      {...props}
    >
      <div
        className="pointer-events-auto relative flex items-center gap-2 rounded-axie-pill border border-axie-line bg-axie-surface/92 p-[7px] shadow-axie-nav backdrop-blur-xl min-[390px]:gap-3"
        ref={navRef}
      >
        <span
          aria-hidden
          className="pointer-events-none absolute left-0 top-0 rounded-axie-pill bg-axie-ink shadow-[inset_0_1px_0_color-mix(in_srgb,var(--axie-color-surface)_16%,transparent),0_8px_22px_color-mix(in_srgb,var(--axie-color-ink)_13%,transparent)] transition-[height,opacity,transform,width] duration-300 ease-[var(--axie-motion-spring)]"
          style={indicatorStyle}
        />
        {items.slice(0, splitIndex).map((item) => (
          <MobileDockLink
            item={item}
            key={item.value}
            selected={selectedValue === item.value}
            setRef={(node) => setDockItemRef(itemRefs.current, item.value, node)}
            onSelect={selectItem}
          />
        ))}
        {action ? <MobileDockCenterAction action={action} /> : null}
        {items.slice(splitIndex).map((item) => (
          <MobileDockLink
            item={item}
            key={item.value}
            selected={selectedValue === item.value}
            setRef={(node) => setDockItemRef(itemRefs.current, item.value, node)}
            onSelect={selectItem}
          />
        ))}
      </div>
    </nav>
  );
}

function MobileDockLink({
  item,
  onSelect,
  selected,
  setRef
}: {
  item: MobileDockItem;
  onSelect: (item: MobileDockItem) => void;
  selected: boolean;
  setRef: (node: HTMLElement | null) => void;
}) {
  const className = cn(
    "relative z-[1] grid h-[45px] w-[52px] place-items-center rounded-axie-pill outline-none transition-[color,transform] duration-300 ease-[var(--axie-motion-spring)] focus-visible:ring-2 focus-visible:ring-axie-accent/20 active:scale-95 min-[390px]:w-[58px]",
    selected ? "text-axie-surface" : "text-axie-muted hover:text-axie-ink",
    item.disabled && "cursor-not-allowed opacity-45 hover:text-axie-muted"
  );
  const content = (
    <>
      <span
        aria-hidden
        className={cn(
          "grid h-5 w-5 place-items-center transition-transform duration-300 ease-[var(--axie-motion-spring)] [&>svg]:h-5 [&>svg]:w-5",
          selected && "scale-105"
        )}
      >
        {item.icon}
      </span>
      <span className="sr-only">{item.label}</span>
    </>
  );

  if (item.href) {
    return (
      <a
        aria-current={selected ? "page" : undefined}
        aria-disabled={item.disabled || undefined}
        aria-label={item.ariaLabel ?? item.label}
        className={className}
        href={item.disabled ? undefined : item.href}
        ref={setRef}
        onClick={(event) => {
          if (item.disabled) {
            event.preventDefault();
            return;
          }
          onSelect(item);
        }}
        onPointerDown={() => onSelect(item)}
      >
        {content}
      </a>
    );
  }

  return (
    <button
      aria-label={item.ariaLabel ?? item.label}
      aria-pressed={selected}
      className={className}
      disabled={item.disabled}
      ref={setRef}
      type="button"
      onClick={() => onSelect(item)}
      onPointerDown={() => onSelect(item)}
    >
      {content}
    </button>
  );
}

function MobileDockCenterAction({ action }: { action: MobileDockAction }) {
  const className =
    "relative z-[1] -my-[22px] grid h-[68px] w-[68px] place-items-center rounded-axie-pill bg-axie-ink text-axie-surface shadow-[0_18px_34px_color-mix(in_srgb,var(--axie-color-ink)_22%,transparent)] outline-none transition duration-200 ease-[var(--axie-motion-spring)] focus-visible:ring-2 focus-visible:ring-axie-accent/20 active:scale-95 disabled:cursor-not-allowed disabled:opacity-55 [&>svg]:h-7 [&>svg]:w-7";

  if (action.href) {
    return (
      <a
        aria-disabled={action.disabled || undefined}
        aria-label={action.ariaLabel ?? action.label}
        className={className}
        href={action.disabled ? undefined : action.href}
        onClick={(event) => {
          if (action.disabled) {
            event.preventDefault();
            return;
          }
          action.onClick?.(event as React.MouseEvent<HTMLElement>);
        }}
      >
        {action.icon}
      </a>
    );
  }

  return (
    <button
      aria-label={action.ariaLabel ?? action.label}
      className={className}
      disabled={action.disabled}
      type="button"
      onClick={(event) => action.onClick?.(event as React.MouseEvent<HTMLElement>)}
    >
      {action.icon}
    </button>
  );
}

function setDockItemRef(
  refs: Map<string, HTMLElement>,
  value: string,
  node: HTMLElement | null
) {
  if (node) {
    refs.set(value, node);
    return;
  }
  refs.delete(value);
}

type ClassValue = string | false | null | undefined;

export function cn(...values: ClassValue[]) {
  return values.filter(Boolean).join(" ");
}

@theme inline {
  --color-axie-ink: var(--axie-color-ink);
  --color-axie-paper: var(--axie-color-paper);
  --color-axie-surface: var(--axie-color-surface);
  --color-axie-surface-soft: var(--axie-color-surface-soft);
  --color-axie-muted: var(--axie-color-muted);
  --color-axie-line: var(--axie-color-line);
  --color-axie-accent: var(--axie-color-accent);
  --color-axie-accent-soft: var(--axie-color-accent-soft);
  --color-axie-danger: var(--axie-color-danger);
  --color-axie-danger-soft: var(--axie-color-danger-soft);
  --color-axie-warning: var(--axie-color-warning);
  --color-axie-warning-soft: var(--axie-color-warning-soft);
  --color-axie-info: var(--axie-color-info);
  --color-axie-info-soft: var(--axie-color-info-soft);
  --radius-axie-card: var(--axie-radius-card);
  --radius-axie-control: var(--axie-radius-control);
  --radius-axie-sheet: var(--axie-radius-sheet);
  --radius-axie-pill: var(--axie-radius-pill);
  --spacing-axie-page: var(--axie-space-page);
  --spacing-axie-xs: var(--axie-space-xs);
  --spacing-axie-sm: var(--axie-space-sm);
  --spacing-axie-md: var(--axie-space-md);
  --spacing-axie-lg: var(--axie-space-lg);
  --spacing-axie-xl: var(--axie-space-xl);
  --spacing-axie-2xl: var(--axie-space-2xl);
  --shadow-axie-raised: 0 16px 36px color-mix(in srgb, var(--axie-color-ink) 10%, transparent);
  --shadow-axie-soft: 0 10px 24px color-mix(in srgb, var(--axie-color-ink) 6%, transparent);
  --shadow-axie-nav: 0 16px 38px color-mix(in srgb, var(--axie-color-ink) 12%, transparent);
}

:root {
  --axie-color-ink: #263024;
  --axie-color-paper: #f4f1e6;
  --axie-color-surface: #fffdf4;
  --axie-color-surface-soft: #e8ead6;
  --axie-color-muted: #68705d;
  --axie-color-line: #d7d2b9;
  --axie-color-accent: #6f7f3f;
  --axie-color-accent-soft: #e0e8c7;
  --axie-color-danger: #a45447;
  --axie-color-danger-soft: #efd8d0;
  --axie-color-warning: #947236;
  --axie-color-warning-soft: #ecdcb8;
  --axie-color-info: #4d6972;
  --axie-color-info-soft: #dce8e6;
  --axie-radius-card: 10px;
  --axie-radius-control: 12px;
  --axie-radius-sheet: 30px;
  --axie-radius-pill: 999px;
  --axie-space-page: 20px;
  --axie-space-xs: 6px;
  --axie-space-sm: 10px;
  --axie-space-md: 14px;
  --axie-space-lg: 20px;
  --axie-space-xl: 28px;
  --axie-space-2xl: 36px;
  --axie-motion-fast: 160ms;
  --axie-motion-base: 240ms;
  --axie-motion-slow: 360ms;
  --axie-motion-ease: cubic-bezier(0.2, 0.9, 0.2, 1);
  --axie-motion-spring: cubic-bezier(0.16, 1, 0.3, 1);
  --axie-motion-pop: cubic-bezier(0.18, 1.24, 0.3, 1);
}

.axie-pressable {
  transform: translate3d(0, 0, 0) scale(1);
  transition-duration: var(--axie-motion-base);
  transition-property: background-color, border-color, box-shadow, color, opacity, transform;
  transition-timing-function: var(--axie-motion-spring);
  will-change: transform;
}

.axie-pressable:hover {
  transform: translate3d(0, -1px, 0) scale(1.005);
}

.axie-pressable:active {
  transform: translate3d(0, 0, 0) scale(0.985);
}

.axie-enter {
  animation: axie-enter var(--axie-motion-slow) var(--axie-motion-spring) both;
}

.axie-pop {
  animation: axie-pop var(--axie-motion-slow) var(--axie-motion-pop) both;
}

.axie-fade {
  animation: axie-fade var(--axie-motion-base) ease-out both;
}

.axie-sheet-backdrop {
  animation: axie-fade var(--axie-motion-fast) ease-out both;
}

.axie-sheet-panel {
  animation: axie-sheet-panel-in var(--axie-motion-slow) var(--axie-motion-ease) both;
}

.axie-row-enter {
  animation: axie-row-in var(--axie-motion-base) var(--axie-motion-ease) both;
  animation-delay: var(--axie-row-delay, 0ms);
}

.axie-slider {
  --axie-slider-fill: 0%;
  -webkit-appearance: none;
  appearance: none;
  block-size: 32px;
  inline-size: 100%;
  margin: 0;
  background: transparent;
  color: var(--axie-color-accent);
  cursor: pointer;
}

.axie-slider:disabled {
  cursor: not-allowed;
  opacity: 0.56;
}

.axie-slider::-webkit-slider-runnable-track {
  block-size: 12px;
  border: 1px solid color-mix(in srgb, var(--axie-color-line) 88%, var(--axie-color-ink));
  border-radius: var(--axie-radius-pill);
  background:
    linear-gradient(
      to right,
      var(--axie-color-accent) 0 var(--axie-slider-fill),
      color-mix(in srgb, var(--axie-color-surface-soft) 84%, var(--axie-color-paper)) var(--axie-slider-fill) 100%
    );
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--axie-color-surface) 74%, transparent);
  transition:
    background var(--axie-motion-base) var(--axie-motion-spring),
    border-color var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  block-size: 22px;
  inline-size: 22px;
  margin-block-start: -6px;
  border: 2px solid var(--axie-color-surface);
  border-radius: 50%;
  background:
    radial-gradient(
      circle at 34% 32%,
      color-mix(in srgb, var(--axie-color-accent-soft) 62%, white) 0 22%,
      var(--axie-color-accent) 58%
    );
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
  transition:
    box-shadow var(--axie-motion-base) var(--axie-motion-spring),
    transform var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider:hover::-webkit-slider-thumb {
  transform: scale(1.05);
}

.axie-slider:active::-webkit-slider-thumb {
  transform: scale(0.94);
}

.axie-slider:focus-visible::-webkit-slider-thumb {
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent),
    0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
}

.axie-slider::-moz-range-track {
  block-size: 12px;
  border: 1px solid color-mix(in srgb, var(--axie-color-line) 88%, var(--axie-color-ink));
  border-radius: var(--axie-radius-pill);
  background: color-mix(in srgb, var(--axie-color-surface-soft) 84%, var(--axie-color-paper));
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--axie-color-surface) 74%, transparent);
}

.axie-slider::-moz-range-progress {
  block-size: 12px;
  border-radius: var(--axie-radius-pill);
  background: var(--axie-color-accent);
}

.axie-slider::-moz-range-thumb {
  box-sizing: border-box;
  block-size: 22px;
  inline-size: 22px;
  border: 2px solid var(--axie-color-surface);
  border-radius: 50%;
  background:
    radial-gradient(
      circle at 34% 32%,
      color-mix(in srgb, var(--axie-color-accent-soft) 62%, white) 0 22%,
      var(--axie-color-accent) 58%
    );
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
  transition:
    box-shadow var(--axie-motion-base) var(--axie-motion-spring),
    transform var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider:hover::-moz-range-thumb {
  transform: scale(1.05);
}

.axie-slider:active::-moz-range-thumb {
  transform: scale(0.94);
}

.axie-slider:focus-visible::-moz-range-thumb {
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent),
    0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
}

@keyframes axie-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes axie-enter {
  from {
    opacity: 0;
    transform: translate3d(0, 10px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-pop {
  from {
    opacity: 0;
    transform: translate3d(0, 12px, 0) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-sheet-panel-in {
  from {
    opacity: 0.72;
    transform: translate3d(0, 26px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-row-in {
  from {
    opacity: 0;
    transform: translate3d(0, 8px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-accordion-down {
  from {
    opacity: 0;
    transform: translate3d(0, -4px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-shimmer {
  100% {
    transform: translateX(100%);
  }
}

@keyframes axie-pulse-dot {
  0%,
  100% {
    box-shadow: 0 0 0 0 color-mix(in srgb, var(--axie-color-accent) 30%, transparent);
  }
  50% {
    box-shadow: 0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 0%, transparent);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-duration: 0.001ms !important;
  }

  .axie-enter,
  .axie-pop,
  .axie-fade,
  .axie-sheet-backdrop,
  .axie-sheet-panel,
  .axie-row-enter {
    animation: none;
  }

  .axie-pressable,
  .axie-pressable:hover,
  .axie-pressable:active {
    transform: none;
  }
}
